.column-settings-wrap {
  position: relative;
}

.column-settings-panel {
  display: none;
  position: absolute;
  top: calc(100% + 4px);
  right: 0;
  min-width: 220px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  z-index: 1000;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
  overflow: hidden;
}

.column-settings-panel.open {
  display: block;
}

.col-settings-header {
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
}

.col-settings-list {
  padding: 4px 0;
}

.col-toggle-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 12px;
  cursor: pointer;
  transition: background var(--duration-fast);
  user-select: none;
}

.col-toggle-item:hover {
  background: var(--bg-hover);
}

.col-toggle-item.locked {
  opacity: 0.5;
  cursor: not-allowed;
}

.col-toggle-item.locked:hover {
  background: transparent;
}

.col-toggle-item.required {
  opacity: 0.7;
}

.col-toggle-label {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: var(--text-primary);
}

.col-lock-icon {
  color: var(--text-muted);
  flex-shrink: 0;
}

/* Toggle switch */
.col-toggle-switch {
  position: relative;
  display: inline-flex;
  align-items: center;
}

.col-toggle-switch input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.col-toggle-track {
  width: 32px;
  height: 18px;
  background: var(--bg-surface-3);
  border: 1px solid var(--border);
  border-radius: 9px;
  position: relative;
  transition: all var(--duration-fast);
  cursor: pointer;
}

.col-toggle-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 12px;
  height: 12px;
  background: var(--text-muted);
  border-radius: 50%;
  transition: all var(--duration-fast);
}

.col-toggle-switch input:checked + .col-toggle-track {
  background: var(--blue-bg);
  border-color: var(--blue);
}

.col-toggle-switch input:checked + .col-toggle-track .col-toggle-thumb {
  transform: translateX(14px);
  background: var(--blue);
}

.col-toggle-switch.disabled {
  pointer-events: none;
}

.col-toggle-switch.disabled .col-toggle-track {
  opacity: 0.4;
}

/* =========================================================================
   Reduced motion
   ========================================================================= */

@media (prefers-reduced-motion: reduce) {

